import React, { useContext, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Dropdown, Container } from 'react-bootstrap'; 
// Importaciones de Contextos
import { AuthContext } from '../context/AuthContext';
import { CartContext } from '../context/CartContext';
import { SettingsContext } from '../context/SettingsContext'; 
// Componentes dependientes
import SearchBox from './SearchBox'; 
// Eliminamos HeaderSkeleton y simplificamos el manejo de carga

const Header = () => {
  const navigate = useNavigate();
  // Renombramos loading para evitar conflictos
  const { userInfo: user, logout } = useContext(AuthContext); 
  const { cartItems, isItemJustAdded } = useContext(CartContext);
  const { settings } = useContext(SettingsContext); // Mantenemos settings para el nombre/eslogan

  useEffect(() => {
    // Aplicar el color de acento de la configuración a las variables CSS globales
    if (settings?.accentColor) {
      document.documentElement.style.setProperty('--cta-color', settings.accentColor);
    }
  }, [settings]);

  const logoutHandler = () => {
    logout();
    navigate('/login');
  };

  // Cálculo de artículos totales para el badge del carrito
  const totalCartItems = cartItems.reduce((acc, item) => acc + item.qty, 0); 
  // Verificar si el usuario tiene permiso para el panel de administración
  const canAccessAdminPanel = user?.permissions?.includes('access:admin_panel');

  // Clases base para enlaces de navegación (elimina subrayado, asegura el color de fondo)
  const baseLinkClasses = "text-gray-300 no-underline hover:text-white transition-colors";
  
  // CRÍTICO: El fondo oscuro del header es crucial para el diseño Tecnotitlan
  return (
    // CRÍTICO: Añadimos rounded-b-xl para redondear las esquinas inferiores
    <header 
      className="w-full sticky top-0 z-50 transition-all duration-300 shadow-md rounded-b-xl"
      // Usamos el color Maestro
      style={{ backgroundColor: 'var(--brand-dark)' }} 
    >
      {/* py-3 para dar espacio arriba y abajo */}
      <Container className="py-3"> 
        {/* CRÍTICO: d-flex para la alineación horizontal de Logo, Search y Acciones */}
        <div className="d-flex justify-content-between align-items-center"> 
          
          {/* 1. Logo de Texto/Eslogan (Izquierda) */}
          <Link 
            to="/" 
            className={`${baseLinkClasses} flex items-center h-full flex-shrink-0`}
          > 
            <div className="d-flex flex-column align-items-start">
              {/* Nombre en mayúsculas, negrita y tamaño grande (text-xl/20px) */}
              <span className="text-white text-xl font-extrabold tracking-widest uppercase" style={{ lineHeight: 1 }}>
                {settings?.siteName || 'TECNOTITLÁN'}
              </span>
              {/* Eslogan en pequeño, opaco y estilo light (text-xs/12px) */}
              <span className="text-gray-400 text-xs font-light tracking-wide mt-0.5" style={{ lineHeight: 1 }}>
                Tecnología con Raíces
              </span>
            </div>
          </Link>

          {/* 2. Barra de búsqueda (Centrada - Oculta en móvil) */}
          <div className="d-none d-lg-block w-1/2 max-w-lg mx-auto px-5">
            {/* Se asume que SearchBox usa el estilo redondeado del mock */}
            <SearchBox /> 
          </div>

          {/* 3. Navegación Derecha (Carrito y Usuario) */}
          <nav className="d-flex align-items-center gap-4 w-auto flex-shrink-0">
            {/* Icono del Carrito */}
            <Link 
              to="/cart" 
              // CRÍTICO: Usamos el color de acento para la animación de 'recién añadido'
              className={`relative ${baseLinkClasses} ${isItemJustAdded ? 'animate-pulse text-white' : ''} flex items-center`}
              style={{ color: isItemJustAdded ? 'var(--cta-color)' : '' }} 
            >
              <i className="fas fa-shopping-cart text-xl"></i>
              <span className="d-none d-md-inline ms-2 font-medium">Carrito</span>
              {totalCartItems > 0 && (
                <span className="absolute -top-2 -right-2 bg-red-600 text-white text-[10px] font-bold px-1.5 py-0.5 rounded-full shadow-sm">
                  {totalCartItems}
                </span>
              )}
            </Link>

            {/* Menú de Usuario/Login */}
            {user ? (
              <Dropdown align="end">
                <Dropdown.Toggle 
                  as="a" 
                  className={`${baseLinkClasses} font-medium gap-2 cursor-pointer text-white no-underline flex items-center`} 
                >
                  {/* Icono de usuario simple (usado en el mock) */}
                  <i className="fas fa-user text-xl"></i> 
                  <span className="d-none d-md-inline">{user.name || 'Super Administrador'}</span>
                </Dropdown.Toggle>

                <Dropdown.Menu className="shadow-xl border-0 rounded-lg mt-2 p-1 bg-white">
                  <Dropdown.Item as={Link} to="/profile" className="rounded py-2">Perfil</Dropdown.Item>
                  {canAccessAdminPanel && (
                    <Dropdown.Item as={Link} to="/admin/dashboard" className="rounded py-2">Panel Admin</Dropdown.Item>
                  )}
                  <Dropdown.Divider className="my-1" />
                  <Dropdown.Item onClick={logoutHandler} className="text-red-600 rounded py-2">Cerrar Sesión</Dropdown.Item>
                </Dropdown.Menu>
              </Dropdown>
            ) : (
              <Link to="/login" className={`${baseLinkClasses} font-medium gap-2 flex items-center`}>
                <i className="fas fa-user text-xl"></i> <span className="d-none d-md-inline">Entrar</span>
              </Link>
            )}
          </nav>
        </div>
        
        {/* Barra de búsqueda (Solo Móvil - Se extiende en su propia fila) */}
        <div className="d-lg-none mt-3">
          <SearchBox />
        </div>
      </Container>
    </header>
  );
};

export default Header;
